-- Security Hardening based on Linter Findings
-- Generated by Antigravity

-- =================================================================
-- 1. Exposed Auth Users
-- =================================================================
-- Revoke access to views exposing auth.users to anon/authenticated
REVOKE ALL ON public.mv_conversion_funnel FROM anon, authenticated;
REVOKE ALL ON public.mv_weekly_cohorts FROM anon, authenticated;

-- =================================================================
-- 2. Security Definer Views
-- =================================================================
-- Convert views to Security Invoker to enforce RLS of the caller
-- (Requires Postgres 15+)
ALTER VIEW public.task_events SET (security_invoker = true);
ALTER VIEW public.target_forms SET (security_invoker = true);
ALTER VIEW public.task_inputs SET (security_invoker = true);
ALTER VIEW public.tasks SET (security_invoker = true);

-- =================================================================
-- 3. Missing RLS
-- =================================================================
-- Enable Row Level Security (Default Deny) on public tables
ALTER TABLE public.user_properties ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.experiments ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.experiment_assignments ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.email_digest_log ENABLE ROW LEVEL SECURITY;
